classDiagram
    class DashboardController {
        -AccountService accountService
        -AnalyticsService analyticsService
        +getDashboardData(userId: UUID): DashboardDTO
    }
    class AccountService {
        -AccountRepository accountRepo
        -CacheManager cache
        +getUserAccounts(userId: UUID): List~Account~
        +getAccountDetails(accountId: UUID): Account
    }
    class AnalyticsService {
        -TransactionRepository txnRepo
        -MLEngineClient mlClient
        +calculateNetWorth(userId: UUID): NetWorthDTO
        +getSpendingTrends(userId: UUID): TrendData
    }
    class AccountRepository {
        +findByUserId(userId: UUID): List~Account~
        +findById(accountId: UUID): Account
    }
    class AccountCardComponent {
        +Account accountData
        +boolean isLoading
        +render(): JSX
        -formatCurrency(amount: number): string
    }
    class SparklineWidget {
        +Array~number~ dataPoints
        +String colorTheme
        +renderChart(): void
    }

    DashboardController --> AccountService
    DashboardController --> AnalyticsService
    AccountService --> AccountRepository
    AccountCardComponent *-- SparklineWidget : composition
